import React, { useState, useMemo } from 'react';

export default function Autocomplete({ items, placeholder = '' }) {
  const [text, setText] = useState('');
  const [open, setOpen] = useState(false);
  const [active, setActive] = useState(-1);

  const matches = useMemo(() => {
    const q = text.trim().toLowerCase();
    if (!q) return [];
    return items.filter((i) => i.toLowerCase().includes(q)).slice(0, 8);
  }, [text, items]);

  const choose = (value) => {
    setText(value);
    setOpen(false);
    setActive(-1);
  };

  const onKeyDown = (e) => {
    if (!open && (e.key === 'ArrowDown' || e.key === 'ArrowUp')) {
      setOpen(true);
      return;
    }
    if (e.key === 'ArrowDown') {
      e.preventDefault();
      setActive((a) => Math.min(a + 1, matches.length - 1));
    } else if (e.key === 'ArrowUp') {
      e.preventDefault();
      setActive((a) => Math.max(a - 1, 0));
    } else if (e.key === 'Enter' && active >= 0 && matches[active]) {
      choose(matches[active]);
    } else if (e.key === 'Escape') {
      setOpen(false);
    }
  };

  return (
    <div style={{ position: 'relative', maxWidth: 320 }}>
      <input
        role="combobox"
        aria-expanded={open && matches.length > 0}
        aria-controls="ac-list"
        aria-activedescendant={active >= 0 ? `ac-opt-${active}` : undefined}
        value={text}
        placeholder={placeholder}
        onChange={(e) => {
          setText(e.target.value);
          setOpen(true);
          setActive(-1);
        }}
        onFocus={() => setOpen(true)}
        onBlur={() => setOpen(false)}
        onKeyDown={onKeyDown}
        style={{ width: '100%', padding: 10, fontSize: 15, boxSizing: 'border-box' }}
      />
      {open && matches.length > 0 && (
        <ul
          id="ac-list"
          role="listbox"
          style={{
            position: 'absolute',
            top: '100%',
            left: 0,
            right: 0,
            margin: '4px 0 0',
            padding: 0,
            listStyle: 'none',
            border: '1px solid #ddd',
            borderRadius: 8,
            background: '#fff',
            boxShadow: '0 6px 20px rgba(0,0,0,0.12)',
            maxHeight: 240,
            overflowY: 'auto',
            zIndex: 10,
          }}
        >
          {matches.map((m, i) => (
            <li
              key={m}
              id={`ac-opt-${i}`}
              role="option"
              aria-selected={i === active}
              onMouseDown={(e) => {
                e.preventDefault();
                choose(m);
              }}
              onMouseEnter={() => setActive(i)}
              style={{
                padding: '8px 12px',
                cursor: 'pointer',
                background: i === active ? '#eef2ff' : '#fff',
              }}
            >
              {m}
            </li>
          ))}
        </ul>
      )}
    </div>
  );
}

