import { Component, Input } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

@Component({
  selector: 'app-autocomplete',
  template: `
    <div style="position: relative; max-width: 320px;">
      <input
        role="combobox"
        [attr.aria-expanded]="open && matches.length > 0"
        [value]="text"
        [placeholder]="placeholder"
        (input)="onInput($any($event.target).value)"
        (focus)="open = true"
        (blur)="open = false"
        (keydown.arrowdown)="$event.preventDefault(); move(1)"
        (keydown.arrowup)="$event.preventDefault(); move(-1)"
        (keydown.enter)="onEnter()"
        (keydown.escape)="open = false"
        style="width: 100%; padding: 10px; font-size: 15px; box-sizing: border-box;"
      />
      <ul
        *ngIf="open && matches.length > 0"
        role="listbox"
        style="position: absolute; top: 100%; left: 0; right: 0; margin: 4px 0 0; padding: 0; list-style: none; border: 1px solid #ddd; border-radius: 8px; background: #fff; box-shadow: 0 6px 20px rgba(0,0,0,0.12); max-height: 240px; overflow-y: auto; z-index: 10;"
      >
        <li
          *ngFor="let m of matches; let i = index"
          role="option"
          [attr.aria-selected]="i === active"
          [style.background]="i === active ? '#eef2ff' : '#fff'"
          (mousedown)="$event.preventDefault(); choose(m)"
          (mouseenter)="active = i"
          style="padding: 8px 12px; cursor: pointer;"
        >{{ m }}</li>
      </ul>
    </div>
  `,
})
export class AutocompleteComponent {
  @Input() items: string[] = [];
  @Input() placeholder = '';
  text = '';
  open = false;
  active = -1;

  get matches(): string[] {
    const q = this.text.trim().toLowerCase();
    if (!q) {
      return [];
    }
    return this.items.filter((i) => i.toLowerCase().indexOf(q) !== -1).slice(0, 8);
  }

  onInput(value: string): void {
    this.text = value;
    this.open = true;
    this.active = -1;
  }

  move(delta: number): void {
    if (!this.open) {
      this.open = true;
      return;
    }
    const next = this.active + delta;
    this.active = Math.max(0, Math.min(next, this.matches.length - 1));
  }

  onEnter(): void {
    if (this.active >= 0 && this.matches[this.active]) {
      this.choose(this.matches[this.active]);
    }
  }

  choose(value: string): void {
    this.text = value;
    this.open = false;
    this.active = -1;
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px;">
      <h1>Autocomplete Demo</h1>
      <app-autocomplete [items]="countries" placeholder="Search countries…"></app-autocomplete>
    </div>
  `,
})
export class AppComponent {
  countries = [
    'Argentina', 'Australia', 'Austria', 'Belgium', 'Brazil', 'Canada', 'Chile',
    'China', 'Denmark', 'Egypt', 'Finland', 'France', 'Germany', 'Greece', 'India',
    'Indonesia', 'Ireland', 'Italy', 'Japan', 'Kenya', 'Mexico', 'Nepal',
    'Netherlands', 'Norway', 'Poland', 'Portugal', 'Spain', 'Sweden', 'Thailand',
    'Turkey', 'Ukraine', 'United Kingdom', 'United States', 'Vietnam',
  ];
}

@NgModule({
  declarations: [AppComponent, AutocompleteComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
